-- Migration: 20260226120000_emergency-client-recovery-system.sql\n\n-- Table: emergency_recovery_tokens\nCREATE TABLE IF NOT EXISTS emergency_recovery_tokens (\n    id SERIAL PRIMARY KEY,\n    token VARCHAR(255) UNIQUE NOT NULL,\n    user_id INT NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    expires_at TIMESTAMP NOT NULL,\n    status VARCHAR(50) DEFAULT 'active'\n);\n\n-- Table: client_provider_audit_log\nCREATE TABLE IF NOT EXISTS client_provider_audit_log (\n    id SERIAL PRIMARY KEY,\n    client_id INT NOT NULL,\n    action VARCHAR(255) NOT NULL,\n    action_timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    details JSONB\n);\n\n-- Table: emergency_recovery_settings\nCREATE TABLE IF NOT EXISTS emergency_recovery_settings (\n    id SERIAL PRIMARY KEY,\n    setting_key VARCHAR(255) UNIQUE NOT NULL,\n    setting_value VARCHAR(255) NOT NULL,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- RPC functions\n\n-- Function for token creation\nCREATE OR REPLACE FUNCTION create_token(user_id INT) RETURNS VARCHAR AS $$\nDECLARE\n    new_token VARCHAR(255) := gen_random_uuid(); -- Generates a unique token\nBEGIN\n    INSERT INTO emergency_recovery_tokens (token, user_id, expires_at)\n    VALUES (new_token, user_id, NOW() + INTERVAL '30 minutes') RETURNING token INTO new_token;\n    RETURN new_token;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Function for client search by contact\nCREATE OR REPLACE FUNCTION search_client_by_contact(contact_info VARCHAR) RETURNS TABLE(client_id INT, client_name VARCHAR) AS $$\nBEGIN\n    RETURN QUERY SELECT id, name FROM clients WHERE contact_info ILIKE '%' || contact_info || '%';\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Function for searching by KID\nCREATE OR REPLACE FUNCTION search_by_kid(kid INT) RETURNS TABLE(client_id INT, client_name VARCHAR) AS $$\nBEGIN\n    RETURN QUERY SELECT c.id, c.name FROM clients c INNER JOIN emergency_recovery_tokens ert ON c.id = ert.user_id WHERE ert.token = kid::VARCHAR;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Function for getting token status\nCREATE OR REPLACE FUNCTION get_token_status(token VARCHAR) RETURNS VARCHAR AS $$\nDECLARE\n    token_status VARCHAR;\nBEGIN\n    SELECT status INTO token_status FROM emergency_recovery_tokens WHERE token = token;\n    RETURN token_status;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Function for completing recovery\nCREATE OR REPLACE FUNCTION complete_recovery(token VARCHAR) RETURNS VOID AS $$\nBEGIN\n    UPDATE emergency_recovery_tokens SET status = 'completed' WHERE token = token;\n    -- Additional logic for completing recovery can be added here\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Function for recovery dashboard data\nCREATE OR REPLACE FUNCTION recovery_dashboard_data() RETURNS TABLE(token_status VARCHAR, total_count INT) AS $$\nBEGIN\n    RETURN QUERY SELECT status, COUNT(*) FROM emergency_recovery_tokens GROUP BY status;\nEND;\n$$ LANGUAGE plpgsql;\n